    /// Legacy light/dark toggle. Kept in sync with `theme` for back-compat;
    /// `theme` is the source of truth.
    pub dark_mode: bool,
    /// Color theme: `dark`, `light`, or `catppuccin-{latte,frappe,macchiato,mocha}`.
    /// Empty in an older config triggers migration from `dark_mode` in sanitize.
    #[serde(default)]
    pub theme: String,
    pub default_endpoint: String,
    pub system_prompt: String,
    pub temperature: f32,
    pub max_tokens: u32,
    pub use_max_tokens: bool,
    pub saved_endpoints: Vec<Endpoint>,
    pub font_family: String,
    pub mono_font_family: String,
    /// Nucleus sampling. `None` (or `< 0`) means "don't send", which is what most
    /// users want — leaving it to the model default.
    pub top_p: Option<f32>,
    pub frequency_penalty: Option<f32>,
    pub presence_penalty: Option<f32>,
    /// Stop sequences. Empty vec → don't send.
    pub stop_sequences: Vec<String>,
    /// Rebindable keyboard shortcuts.
    pub hotkeys: Hotkeys,
    /// MCP servers to connect to.
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub mcp_servers: Vec<McpServer>,
    /// Retention window for the recorded usage history, in days. `0` (the
    /// default) keeps everything forever; any positive value prunes usage rows
    /// older than that many days (on startup and whenever the Usage page loads).
    #[serde(default)]
    pub usage_retention_days: u32,
}

impl Default for Config {
    fn default() -> Self {
        Self {
            font_size: 14.0,
            mono_font_size: 13.0,
            ui_scale: 1.0,
            dark_mode: true,
            theme: "dark".to_string(),
            default_endpoint: "http://localhost:1234/v1".to_string(),
            system_prompt: String::new(),
            temperature: 0.7,
            max_tokens: 2048,

