pub fn load_conversation_settings(&self, id: i64) -> ConversationSettings {
    self.conn
        .query_row(
            "SELECT model, system_prompt, temperature, max_tokens, use_max_tokens,
                    top_p, frequency_penalty, presence_penalty, stop_sequences, endpoint,
                    working_dir
             FROM conversations WHERE id = ?1",
            params![id],
            |row| {
                let stop_json: Option<String> = row.get(8).ok();
                let stop_sequences = stop_json
                    .as_deref()
                    .and_then(|s| serde_json::from_str::<Vec<String>>(s).ok())
                    .unwrap_or_default();
                Ok(ConversationSettings {
                    model: row.get(0).ok(),
                    system_prompt: row.get(1).ok(),
                    temperature: row.get::<_, Option<f64>>(2).ok().flatten().map(|v| v as f32),
                    max_tokens: row.get::<_, Option<i64>>(3).ok().flatten().map(|v| v as u32),
                    use_max_tokens: row.get::<_, i64>(4).unwrap_or(0) != 0,
                    top_p: row.get::<_, Option<f64>>(5).ok().flatten().map(|v| v as f32),
                    frequency_penalty: row
                        .get::<_, Option<f64>>(6)
                        .ok()
                        .flatten()
                        .map(|v| v as f32),
                    presence_penalty: row
                        .get::<_, Option<f64>>(7)
                        .ok()
                        .flatten()
                        .map(|v| v as f32),
                    stop_sequences,
                    endpoint: row.get(9).ok(),
                    working_dir: row.get(10).ok(),
                })
            },
        )
        .unwrap_or_default()
}

pub fn save_conversation_settings(&self, id: i64, s: &ConversationSettings) {
    let stop_json = if s.stop_sequences.is_empty() {
        None
    } else {
        serde_json::to_string(&s.stop_sequences).ok()
    };
    self.conn
        .execute(
            "UPDATE conversations
             SET model = ?1, system_prompt = ?2, temperature = ?3, max_tokens = ?4,
                 use_max_tokens = ?5, top_p = ?6, frequency_penalty = ?7,
                 presence_penalty = ?8, stop_sequences = ?9, endpoint = ?10,
                 working_dir = ?11,
                 updated_at = datetime('now')
             WHERE id = ?12",
            params![
                s.model,
                s.system_prompt,
                s.temperature.map(|v| v as f64),
                s.max_tokens.map(|v| v as i64),
                s.use_max_tokens as i64,
                s.top_p.map(|v| v as f64),
                s.frequency_penalty.map(|v| v as f64),
                s.presence_penalty.map(|v| v as f64),
                stop_json,
                s.endpoint,
                s.working_dir,
                id,
            ],
        )
        .ok();
}

pub fn set_pinned(&self, id: i64, pinned: bool) {
    self.conn
        .execute(
            "UPDATE conversations SET pinned = ?1 WHERE id = ?2",
            params![pinned as i64, id],
        )
        .ok();
}

pub fn save_draft(&self, id: i64, draft: &str) {
    self.conn
        .execute(
            "UPDATE conversations SET draft = ?1 WHERE id = ?2",
            params![draft, id],
        )
        .ok();
}

#[derive(Serialize, Clone, Debug)]
pub struct Endpoint {
    pub url: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub api_key: Option<String>,
    /// Inference runtime behind this endpoint (for metrics interpretation).
    #[serde(default, skip_serializing_if = "runtime_is_default")]
    pub runtime: Runtime,
    /// Prometheus `/metrics` URL to scrape (vLLM, or llama.cpp with `--metrics`).
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub prometheus_url: Option<String>,
    /// GPU metrics source for this endpoint's host.
    #[serde(default, skip_serializing_if = "gpu_is_default")]
    pub gpu: GpuKind,
    /// `fornax-agent` base URL when `gpu = agent` (e.g. http://spark:9099).
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub agent_url: Option<String>,
}

impl<'de> Deserialize<'de> for Endpoint {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        #[derive(Deserialize)]
        #[serde(untagged)]
        enum EndpointRepr {
            Simple(String),
            Full {
                url: String,
                #[serde(default)]
                api_key: Option<String>,
                #[serde(default)]
                runtime: Runtime,
                #[serde(default)]
                prometheus_url: Option<String>,
                #[serde(default)]
                gpu: GpuKind,
                #[serde(default)]
                agent_url: Option<String>,
            },
        }

        match EndpointRepr::deserialize(deserializer)? {
            EndpointRepr::Simple(url) => Ok(Endpoint::new(url)),
            EndpointRepr::Full {
                url,
                api_key,
                runtime,
                prometheus_url,
                gpu,
                agent_url,
            } => Ok(Endpoint {
                url,
                api_key,
                runtime,
                prometheus_url,
                gpu,
                agent_url,
            }),
        }
    }
}

impl Endpoint {
    pub fn new(url: impl Into<String>) -> Self {
        Self {
            url: url.into(),
            api_key: None,
            runtime: Runtime::default(),
            prometheus_url: None,
            gpu: GpuKind::default(),
            agent_url: None,
        }
    }

